/**
 * Email notification handler — formats and sends email notifications
 * for order status changes.
 *
 * Subscribes to EventBus events following the same pattern as
 * NotificationService, providing email-specific formatting for each
 * order status transition.
 *
 * Depends on:
 * - EventBus (event system) for receiving order events
 */

import type { EventBus } from '../events/event-bus.js';
import type { OrderCreatedEvent, OrderStatusChangedEvent } from '../events/event-types.js';
import type { OrderStatus } from '../models/order.js';
import { Logger } from '../utils/logger.js';

export interface EmailMessage {
  id: string;
  to: string;
  subject: string;
  htmlBody: string;
  textBody: string;
  sentAt: Date;
}

const statusMessages: Record<OrderStatus, { subject: string; heading: string; message: string }> = {
  pending: {
    subject: 'Order Received',
    heading: 'We received your order',
    message: 'Your order has been received and is awaiting confirmation.',
  },
  confirmed: {
    subject: 'Order Confirmed',
    heading: 'Your order is confirmed',
    message: 'Great news! Your order has been confirmed and is being prepared.',
  },
  shipped: {
    subject: 'Order Shipped',
    heading: 'Your order is on the way',
    message: 'Your order has been shipped and is on its way to you.',
  },
  delivered: {
    subject: 'Order Delivered',
    heading: 'Your order has been delivered',
    message: 'Your order has been delivered. We hope you enjoy your purchase!',
  },
  cancelled: {
    subject: 'Order Cancelled',
    heading: 'Your order has been cancelled',
    message: 'Your order has been cancelled. If you did not request this, please contact support.',
  },
};

let nextEmailId = 1;

function generateEmailId(): string {
  return `email-${String(nextEmailId++).padStart(4, '0')}`;
}

export function resetEmailIdCounter(): void {
  nextEmailId = 1;
}

export class EmailNotificationHandler {
  private logger = new Logger('EmailNotificationHandler');
  private sentEmails: EmailMessage[] = [];

  constructor(private eventBus: EventBus) {
    this.registerHandlers();
  }

  private registerHandlers(): void {
    this.eventBus.on<OrderCreatedEvent>('order:created', (event) => {
      this.handleOrderCreated(event);
    });

    this.eventBus.on<OrderStatusChangedEvent>('order:status-changed', (event) => {
      this.handleOrderStatusChanged(event);
    });
  }

  private handleOrderCreated(event: OrderCreatedEvent): void {
    this.logger.info(`Sending order confirmation email for order ${event.order.id}`);

    const itemRows = event.order.items
      .map((item) => `<tr><td>${item.name}</td><td>${item.quantity}</td><td>$${item.unitPrice.toFixed(2)}</td></tr>`)
      .join('\n');

    const itemList = event.order.items
      .map((item) => `- ${item.name} x${item.quantity} @ $${item.unitPrice.toFixed(2)}`)
      .join('\n');

    const htmlBody = [
      `<h1>Thank you for your order!</h1>`,
      `<p>Hi ${event.user.name},</p>`,
      `<p>Your order <strong>${event.order.id}</strong> has been placed successfully.</p>`,
      `<table><thead><tr><th>Item</th><th>Qty</th><th>Price</th></tr></thead>`,
      `<tbody>${itemRows}</tbody></table>`,
      `<p><strong>Total: $${event.order.total.toFixed(2)}</strong></p>`,
    ].join('\n');

    const textBody = [
      `Thank you for your order!`,
      ``,
      `Hi ${event.user.name},`,
      `Your order ${event.order.id} has been placed successfully.`,
      ``,
      `Items:`,
      itemList,
      ``,
      `Total: $${event.order.total.toFixed(2)}`,
    ].join('\n');

    this.sendEmail({
      to: event.user.email,
      subject: `Order Confirmation: ${event.order.id}`,
      htmlBody,
      textBody,
    });
  }

  private handleOrderStatusChanged(event: OrderStatusChangedEvent): void {
    const newStatus = event.newStatus as OrderStatus;
    const template = statusMessages[newStatus];

    this.logger.info(
      `Sending status email for order ${event.order.id}: ${event.previousStatus} -> ${event.newStatus}`,
    );

    const htmlBody = [
      `<h1>${template.heading}</h1>`,
      `<p>${template.message}</p>`,
      `<p>Order: <strong>${event.order.id}</strong></p>`,
      `<p>Status: ${event.previousStatus} &rarr; ${event.newStatus}</p>`,
    ].join('\n');

    const textBody = [
      template.heading,
      ``,
      template.message,
      ``,
      `Order: ${event.order.id}`,
      `Status: ${event.previousStatus} -> ${event.newStatus}`,
    ].join('\n');

    this.sendEmail({
      to: event.order.userId,
      subject: `${template.subject} — ${event.order.id}`,
      htmlBody,
      textBody,
    });
  }

  private sendEmail(params: {
    to: string;
    subject: string;
    htmlBody: string;
    textBody: string;
  }): void {
    const email: EmailMessage = {
      id: generateEmailId(),
      to: params.to,
      subject: params.subject,
      htmlBody: params.htmlBody,
      textBody: params.textBody,
      sentAt: new Date(),
    };
    this.sentEmails.push(email);
    this.logger.info(`Email sent: ${email.id} to ${params.to}`);
  }

  getSentEmails(): EmailMessage[] {
    return [...this.sentEmails];
  }

  getSentEmailsForRecipient(recipient: string): EmailMessage[] {
    return this.sentEmails.filter((e) => e.to === recipient);
  }

  getSentEmailCount(): number {
    return this.sentEmails.length;
  }

  clearSentEmails(): void {
    this.sentEmails = [];
  }
}

import { describe, it, expect, beforeEach } from 'vitest';
import { EventBus } from '../../src/events/event-bus.js';
import {
  EmailNotificationHandler,
  resetEmailIdCounter,
} from '../../src/notifications/email-handler.js';
import type { OrderCreatedEvent, OrderStatusChangedEvent } from '../../src/events/event-types.js';

describe('EmailNotificationHandler', () => {
  let eventBus: EventBus;
  let handler: EmailNotificationHandler;

  beforeEach(() => {
    eventBus = new EventBus();
    handler = new EmailNotificationHandler(eventBus);
    resetEmailIdCounter();
  });

  describe('order:created emails', () => {
    const createdEvent: OrderCreatedEvent = {
      type: 'order:created',
      order: {
        id: 'order-1',
        userId: 'user-1',
        items: [
          { productId: 'p1', name: 'Widget', quantity: 2, unitPrice: 10 },
          { productId: 'p2', name: 'Gadget', quantity: 1, unitPrice: 25 },
        ],
        total: 45,
        status: 'pending',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      user: {
        id: 'user-1',
        name: 'Alice',
        email: 'alice@example.com',
        role: 'member',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      timestamp: new Date(),
    };

    it('should send confirmation email on order created', async () => {
      await eventBus.emit(createdEvent);

      const emails = handler.getSentEmails();
      expect(emails).toHaveLength(1);
      expect(emails[0]?.to).toBe('alice@example.com');
      expect(emails[0]?.subject).toContain('Order Confirmation');
      expect(emails[0]?.subject).toContain('order-1');
    });

    it('should include items in HTML body', async () => {
      await eventBus.emit(createdEvent);

      const email = handler.getSentEmails()[0]!;
      expect(email.htmlBody).toContain('Widget');
      expect(email.htmlBody).toContain('Gadget');
      expect(email.htmlBody).toContain('$45.00');
    });

    it('should include items in text body', async () => {
      await eventBus.emit(createdEvent);

      const email = handler.getSentEmails()[0]!;
      expect(email.textBody).toContain('Widget x2');
      expect(email.textBody).toContain('Gadget x1');
      expect(email.textBody).toContain('$45.00');
    });

    it('should include user name in email body', async () => {
      await eventBus.emit(createdEvent);

      const email = handler.getSentEmails()[0]!;
      expect(email.htmlBody).toContain('Alice');
      expect(email.textBody).toContain('Alice');
    });
  });

  describe('order:status-changed emails', () => {
    function makeStatusEvent(
      previousStatus: string,
      newStatus: string,
    ): OrderStatusChangedEvent {
      return {
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [],
          total: 20,
          status: newStatus as 'confirmed',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus,
        newStatus,
        timestamp: new Date(),
      };
    }

    it('should send email on status change to confirmed', async () => {
      await eventBus.emit(makeStatusEvent('pending', 'confirmed'));

      const emails = handler.getSentEmails();
      expect(emails).toHaveLength(1);
      expect(emails[0]?.subject).toContain('Order Confirmed');
      expect(emails[0]?.subject).toContain('order-1');
      expect(emails[0]?.htmlBody).toContain('confirmed');
      expect(emails[0]?.textBody).toContain('confirmed');
    });

    it('should send email on status change to shipped', async () => {
      await eventBus.emit(makeStatusEvent('confirmed', 'shipped'));

      const emails = handler.getSentEmails();
      expect(emails).toHaveLength(1);
      expect(emails[0]?.subject).toContain('Order Shipped');
      expect(emails[0]?.htmlBody).toContain('on the way');
      expect(emails[0]?.textBody).toContain('on the way');
    });

    it('should send email on status change to delivered', async () => {
      await eventBus.emit(makeStatusEvent('shipped', 'delivered'));

      const emails = handler.getSentEmails();
      expect(emails).toHaveLength(1);
      expect(emails[0]?.subject).toContain('Order Delivered');
      expect(emails[0]?.htmlBody).toContain('delivered');
    });

    it('should send email on status change to cancelled', async () => {
      await eventBus.emit(makeStatusEvent('pending', 'cancelled'));

      const emails = handler.getSentEmails();
      expect(emails).toHaveLength(1);
      expect(emails[0]?.subject).toContain('Order Cancelled');
      expect(emails[0]?.htmlBody).toContain('cancelled');
      expect(emails[0]?.textBody).toContain('contact support');
    });

    it('should include previous and new status in email body', async () => {
      await eventBus.emit(makeStatusEvent('pending', 'confirmed'));

      const email = handler.getSentEmails()[0]!;
      expect(email.textBody).toContain('pending');
      expect(email.textBody).toContain('confirmed');
    });

    it('should send to order userId', async () => {
      await eventBus.emit(makeStatusEvent('pending', 'confirmed'));

      expect(handler.getSentEmails()[0]?.to).toBe('user-1');
    });
  });

  describe('email management', () => {
    it('should count sent emails', async () => {
      expect(handler.getSentEmailCount()).toBe(0);

      await eventBus.emit({
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [],
          total: 20,
          status: 'confirmed',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'pending',
        newStatus: 'confirmed',
        timestamp: new Date(),
      });

      expect(handler.getSentEmailCount()).toBe(1);
    });

    it('should filter emails by recipient', async () => {
      await eventBus.emit({
        type: 'order:created',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
          total: 10,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      });

      expect(handler.getSentEmailsForRecipient('alice@example.com')).toHaveLength(1);
      expect(handler.getSentEmailsForRecipient('bob@example.com')).toHaveLength(0);
    });

    it('should clear sent emails', async () => {
      await eventBus.emit({
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [],
          total: 20,
          status: 'confirmed',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'pending',
        newStatus: 'confirmed',
        timestamp: new Date(),
      });

      handler.clearSentEmails();
      expect(handler.getSentEmailCount()).toBe(0);
    });

    it('should generate sequential email IDs', async () => {
      await eventBus.emit({
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [],
          total: 20,
          status: 'confirmed',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'pending',
        newStatus: 'confirmed',
        timestamp: new Date(),
      });
      await eventBus.emit({
        type: 'order:status-changed',
        order: {
          id: 'order-2',
          userId: 'user-1',
          items: [],
          total: 30,
          status: 'shipped',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'confirmed',
        newStatus: 'shipped',
        timestamp: new Date(),
      });

      const emails = handler.getSentEmails();
      expect(emails[0]?.id).toBe('email-0001');
      expect(emails[1]?.id).toBe('email-0002');
    });
  });

  describe('integration with EventBus', () => {
    it('should handle both order:created and order:status-changed events', async () => {
      await eventBus.emit({
        type: 'order:created',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
          total: 10,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      });

      await eventBus.emit({
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [],
          total: 10,
          status: 'confirmed',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'pending',
        newStatus: 'confirmed',
        timestamp: new Date(),
      });

      const emails = handler.getSentEmails();
      expect(emails).toHaveLength(2);
      expect(emails[0]?.subject).toContain('Order Confirmation');
      expect(emails[1]?.subject).toContain('Order Confirmed');
    });

    it('should coexist with NotificationService on the same EventBus', async () => {
      // Import NotificationService to verify they don't interfere
      const { NotificationService } = await import(
        '../../src/services/notification.service.js'
      );
      const notifService = new NotificationService(eventBus);

      await eventBus.emit({
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [],
          total: 20,
          status: 'confirmed',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'pending',
        newStatus: 'confirmed',
        timestamp: new Date(),
      });

      // Both handlers should receive the event
      expect(handler.getSentEmailCount()).toBe(1);
      expect(notifService.getNotificationCount()).toBe(1);
    });
  });
});

